class Solution {
public:
    int compress(vector<char>& chars) {
        int i = 0;
        for (int j = 0; j < chars.size(); ) {
            int count = 1;
            while (j + 1 < chars.size() && chars[j] == chars[j + 1]) {
                j++;
                count++;
            }
            chars[i++] = chars[j];
            if (count > 1) {
                for (char c : to_string(count)) {
                    chars[i++] = c;
                }
            }
            j++;
        }
        return i;
    }
};
```
